#include <vector>
#include <algorithm>

int partition(std::vector<int>& a, int l, int h);
void quicksort(std::vector<int>& a, int l, int h);

void adaptive_sort(std::vector<int>& a) {
    if (a.size() < 2 || std::is_sorted(a.begin(), a.end())) return;
    quicksort(a, 0, (int)a.size() - 1);
}

void quicksort(std::vector<int>& a, int l, int h) {
    while (l < h) {
        int p = partition(a, l, h);
        if (p - l < h - p) { quicksort(a, l, p - 1); l = p + 1; }
        else { quicksort(a, p + 1, h); h = p - 1; }
    }
}

int partition(std::vector<int>& a, int l, int h) {
    int m = l + (h - l) / 2;
    if (a[m] < a[l]) std::swap(a[m], a[l]);
    if (a[h] < a[l]) std::swap(a[h], a[l]);
    if (a[h] < a[m]) std::swap(a[h], a[m]);
    std::swap(a[m], a[h]);
    int p = a[h], i = l;
    for (int j = l; j < h; j++) if (a[j] < p) std::swap(a[i++], a[j]);
    std::swap(a[i], a[h]);
    return i;
}

